function pfShuffle(a){for(var i=a.length-1;i>0;i--){var j=Math.floor(Math.random()*(i+1));var t=a[i];a[i]=a[j];a[j]=t;}return a;}
function wallRows(){var pool=pfShuffle(PORTFOLIO.slice());var _mob=(typeof window!=="undefined"&&window.innerWidth<=820);var _q=_mob?"mqdefault":"hqdefault";var _l=_mob?"lazy":"eager";var dirs=["l","r","l","r","l"],durs=[40,46,34,50,42],per=_mob?5:10,_R=_mob?2:5,out="";for(var r=0;r<_R;r++){var s=pool.slice(r*per,r*per+per);if(s.length<per)s=s.concat(pool.slice(0,per-s.length));var t=s.map(function(v){return '<div class="hw-tile" data-v="'+v+'"><img src="https://i.ytimg.com/vi/'+v+'/'+_q+'.jpg" loading="'+_l+'" onload="if(this.naturalWidth<121){var x=this.parentNode;if(x)x.remove();}" alt=""></div>';}).join("");out+='<div class="hw-row '+dirs[r]+'" style="animation-duration:'+durs[r]+'s">'+t+t+'</div>';}return out;}
function upgradeWall(){if(typeof window!=="undefined"&&window.innerWidth<=820)return;var wall=document.getElementById("heroWall");if(!wall)return;var rows=wall.querySelectorAll(".hw-row"),picks=[];rows.forEach(function(row){var tiles=row.querySelectorAll(".hw-tile");var half=Math.floor(tiles.length/2)||tiles.length;var idx=[];for(var k=0;k<half;k++)idx.push(k);for(var z=idx.length-1;z>0;z--){var j=Math.floor(Math.random()*(z+1));var tt=idx[z];idx[z]=idx[j];idx[j]=tt;}var cnt=Math.min(half,7);for(var m=0;m<cnt;m++)picks.push(tiles[idx[m]]);});picks.forEach(function(tile,i){setTimeout(function(){var v=tile.getAttribute("data-v");if(!v||tile.querySelector("iframe"))return;var f=document.createElement("iframe");f.setAttribute("allow","autoplay");f.setAttribute("tabindex","-1");f.setAttribute("aria-hidden","true");f.src="https://www.youtube-nocookie.com/embed/"+v+"?autoplay=1&mute=1&loop=1&playlist="+v+"&controls=0&modestbranding=1&playsinline=1&rel=0&disablekb=1&fs=0&iv_load_policy=3&vq=large";tile.appendChild(f);},i*120);});}
