function markConsultRead(rec,side){if(!rec)return;var id=rec.id||localStorage.getItem("knollad_consult_id");if(!id)return;var msgs=rec.messages||[];var other=side==="adm"?"cust":"knoll";var field=side==="adm"?"read_adm":"read_vis";var cur=rec[field]||"";var hasNew=msgs.some(function(n){return (n.role===other||(other==="cust"&&n.who==="고객")||(other==="knoll"&&n.who==="크놀AD"))&&(!cur||String(n.at||"")>String(cur));});if(!hasNew)return;var now=new Date().toISOString();rec[field]=now;var body={};body[field]=now;fetch(SUPA_URL+"/rest/v1/knollad_consults?id=eq."+id,{method:"PATCH",headers:Object.assign({"Content-Type":"application/json","Prefer":"return=minimal"},SH),body:JSON.stringify(body)}).catch(function(){});}
