function csBubble(m,idx,arr){const mine=(m.role==="cust"||m.who==="고객"||(S.cust&&m.who===S.cust.name));const t=m.at?new Date(m.at).toLocaleTimeString("ko-KR",{hour:"2-digit",minute:"2-digit",hour12:false,timeZone:"Asia/Seoul"}):"";const _isAdm=(S.role==="admin"||S.role==="cs");const _rec=_isAdm?((S.consults||[]).find(function(x){return String(x.id)===String(S.consultId);})):window._consultRec;const _mySide=_isAdm?"knoll":"cust";const _oRead=_rec?(_isAdm?_rec.read_vis:_rec.read_adm):null;const _seen=_isAdm&&(m.role===_mySide)&&m.at&&_oRead&&(String(_oRead)>=String(m.at));const _rd=_seen?'<span style="font-size:10px;color:#3182F6;font-weight:700;flex-shrink:0">읽음</span>':'';if(mine){return `<div style="display:flex;justify-content:flex-end;align-items:flex-end;gap:6px">${_rd}<span style="font-size:11px;color:#111827;font-weight:600;flex-shrink:0">${t}</span><div style="max-width:74%;background:#3182F6;color:#fff;padding:10px 14px;border-radius:18px 18px 5px 18px;font-size:14.5px;line-height:1.45;word-break:break-word;box-shadow:0 2px 6px rgba(49,130,246,.25)">${esc(m.text||"")}</div></div>`;}return `<div style="display:flex;justify-content:flex-start;align-items:flex-end;gap:7px"><div style="width:28px;height:28px;border-radius:50%;background:#fff;display:flex;align-items:center;justify-content:center;flex-shrink:0;box-shadow:0 1px 3px rgba(0,0,0,.12)">${logoMark('w-5 h-5')}</div><div style="max-width:72%;background:#fff;color:#191F28;padding:10px 14px;border-radius:18px 18px 18px 5px;font-size:14.5px;line-height:1.45;word-break:break-word;box-shadow:0 1px 3px rgba(0,0,0,.07)">${esc(m.text||"")}</div><span style="font-size:11px;color:#111827;font-weight:600;flex-shrink:0">${t}</span>${_rd}</div>`;}
