function toggleConsult(){var p=document.getElementById("consultPanel");if(!p)return;_consultOpen=!_consultOpen;p.style.display=_consultOpen?"block":"none";if(_consultOpen){consultInit();_consultTimer=setInterval(function(){var id=localStorage.getItem("knollad_consult_id");if(id&&_consultOpen)consultLoadThread(id,true);},5000);}else if(_consultTimer){clearInterval(_consultTimer);_consultTimer=null;}}
