function consultStart(){var _lg=!!(typeof S!=="undefined"&&S.cust);var n=(gv("cs_name")||"").trim()||(_lg?(S.cust.brand||S.cust.name):"")||"고객",m=(gv("cs_send")||"").trim();if(!m){toast("메시지를 입력하세요");return;}var msg={who:n,role:"cust",text:m,at:new Date().toISOString()};try{notifyTelegram("💬 [실시간 상담] "+n+": "+m);}catch(_te){}fetch(SUPA_URL+"/rest/v1/knollad_consults",{method:"POST",headers:Object.assign({"Content-Type":"application/json","Prefer":"return=representation"},SH),body:JSON.stringify({name:n,contact:"",messages:[msg],last_at:new Date().toISOString(),status:"진행중",src:_lg?"login":"home",cust_email:_lg?(S.cust.email||""):"",cust_brand:_lg?(S.cust.brand||S.cust.name||""):"",cust_role:_lg?(S.cust.role||""):""})}).then(r=>r.json()).then(function(rows){var id=rows&&rows[0]&&rows[0].id;if(id){localStorage.setItem("knollad_consult_id",id);window._consultRec=rows[0];window._consultCount=-1;consultRenderThread(rows[0]);}else toast("전송 실패");}).catch(()=>toast("오류"));}
