function consultSend(){var id=localStorage.getItem("knollad_consult_id");if(!id)return;var t=(gv("cs_send")||"").trim();if(!t)return;var rec=window._consultRec||{messages:[]};var msgs=(rec.messages||[]).slice();msgs.push({who:rec.name||"고객",role:"cust",text:t,at:new Date().toISOString()});rec.messages=msgs;window._consultRec=rec;consultRenderThread(rec);try{notifyTelegram("💬 [실시간 상담] "+(rec.name||"고객")+": "+t);}catch(_te){}fetch(SUPA_URL+"/rest/v1/knollad_consults?id=eq."+id,{method:"PATCH",headers:Object.assign({"Content-Type":"application/json","Prefer":"return=minimal"},SH),body:JSON.stringify({messages:msgs,last_at:new Date().toISOString(),status:"진행중"})}).catch(()=>{});}
