function fv(k){return esc((S.form&&S.form[k])||"");}
function chPreview(){var top=CH.slice(0,5);var more=Math.max(0,CH.length-top.length);var items=top.map(function(c){return '<button type="button" onclick="openPicker()" class="flex flex-col items-center gap-1.5 flex-shrink-0" style="width:76px">'+logoEl(c,"w-[60px] h-[60px] text-lg")+'<span class="text-[12px] font-bold text-g800 leading-tight text-center truncate w-full">'+esc(c.name)+'</span></button>';}).join("");var moreBtn=more>0?'<button type="button" onclick="openPicker()" class="cn-morebtn flex flex-col items-center gap-1.5 flex-shrink-0" style="width:76px"><div class="cn-more w-[60px] h-[60px] flex items-center justify-center font-bold text-[15px]"><span>+'+more+'</span></div><span class="text-[12px] font-bold text-blue leading-tight text-center">더보기</span></button>':"";return '<style>@keyframes cnShine{0%{transform:translateX(-140%)}55%,100%{transform:translateX(240%)}}@keyframes cnHalo{0%,100%{border-color:#d7e3f8;box-shadow:0 0 0 0 rgba(91,155,255,.10)}50%{border-color:#9fc0ff;box-shadow:0 0 10px 1px rgba(91,155,255,.30)}}.cn-more{position:relative;overflow:hidden;border-radius:20px;background:#fff;border:1.5px solid #d7e3f8;animation:cnHalo 2.8s ease-in-out infinite;transition:transform .2s ease}.cn-more::after{content:"";position:absolute;top:0;left:0;width:45%;height:100%;background:linear-gradient(90deg,transparent,rgba(91,155,255,.18),transparent);transform:translateX(-140%);animation:cnShine 2.8s ease-in-out infinite;z-index:1}.cn-more>span{position:relative;z-index:2;color:#3d7dff}.cn-morebtn:hover .cn-more{border-color:#5b9bff}@media(prefers-reduced-motion:reduce){.cn-more,.cn-more::after{animation:none}}</style><div class="flex gap-2 overflow-x-auto py-2.5 mb-2" style="scrollbar-width:none;-webkit-overflow-scrolling:touch">'+items+moreBtn+'</div>';}
function chSelectBtn(){return `<button type="button" onclick="openPicker()" class="w-full flex items-center gap-3 px-5 py-4 rounded-[20px] bg-g100 border border-g300 hover:border-blue/40 transition-all text-left"><i data-lucide="layers" class="w-[18px] h-[18px] text-g500"></i><span class="flex-1 text-[17px] text-g500">채널 목록에서 선택하기 (복수 선택 가능)</span><i data-lucide="chevron-right" class="w-[18px] h-[18px] text-g400"></i></button>`;}
function applyFields(){return `<div class="space-y-4">${(S.cust&&S.cust.role==="파트너사")?('<div class="bg-blue-soft rounded-2xl p-3"><label class="block text-[14px] font-bold text-g700 mb-1">담당자 <span class="text-blue">*</span></label><input id="f_manager" list="mgrDL" value="'+(fv("manager")||"")+'" placeholder="담당자 선택 또는 새 이름 입력" class="'+INPUT+'"><datalist id="mgrDL">'+((S.myCampsAll||[]).reduce(function(a,c){var mm=c.manager;if(mm&&a.indexOf(mm)<0)a.push(mm);return a;},[]).map(function(mm){return '<option value="'+esc(mm)+'">';}).join(''))+'</datalist><p class="text-[12px] text-g500 mt-1">담당자별로 캠페인·할 일이 구분됩니다.</p></div>'):""}
<div class="${(S.cust&&S.cust.role==="파트너사")?"":"grid grid-cols-1 sm:grid-cols-2 gap-3"}">${(S.cust&&S.cust.role==="파트너사")?"":field('담당자명 <span class="text-blue">*</span>',`<input id="f_name" value="${fv('name')}" placeholder="홍길동" class="${INPUT}">`)}${field('이메일 <span class="text-blue">*</span>',`<input id="f_email" value="${fv('email')}" type="email" placeholder="name@company.com" class="${INPUT}">`)}</div>
<div class="${(S.cust&&S.cust.role==="파트너사")?"":"grid grid-cols-1 sm:grid-cols-2 gap-3"}">${(S.cust&&S.cust.role==="파트너사")?"":field('연락처 <span class="text-blue">*</span>',`<input id="f_phone" value="${fv('phone')}" placeholder="010-0000-0000" class="${INPUT}">`)}${field('브랜드 / 회사명 <span class="text-blue">*</span>',`<input id="f_brand" value="${fv('brand')}" placeholder="브랜드 / 회사명" class="${INPUT}">`)}</div>
<div class="grid grid-cols-1 sm:grid-cols-2 gap-3">${field('업로드 희망일',`<input id="f_date" value="${fv('date')}" type="date" class="${INPUT}">`)}${field('제품 링크',`<input id="f_link" value="${fv('link')}" placeholder="https://" class="${INPUT}">`)}</div>
<div class="pt-1"><label class="block text-[16.5px] font-bold text-g900 mb-2">✨ 희망 채널 선택 <span class="text-[14px] font-normal text-g400 ml-1.5">(더 많은 채널은 ‘더보기’를 클릭해 확인해 주세요)</span></label>${chPreview()}${chSelectBtn()}<div id="selBox" class="${SEL.size?'mt-3':''}">${SEL.size?selectedSummary():''}</div></div>
${field('활용 소재',`<textarea id="f_material" rows="2" placeholder="영상, 이미지, 직접 제작 등 (여러 개는 줄바꿈으로 입력)" class="${INPUT} resize-none">${fv('material')}</textarea>`)}
${field('광고 고지 방식',`<select id="f_ad" class="${INPUT}"><option ${S.form.ad==='광고표기 희망'?'selected':''}>광고표기 희망</option><option ${S.form.ad==='광고 미표기 희망'?'selected':''}>광고 미표기 희망</option><option ${S.form.ad==='별도 협의'?'selected':''}>별도 협의</option></select>`)}
${field('희망 영상 컨셉',`<textarea id="f_concept" rows="2" placeholder="분위기, 스타일, 레퍼런스 등을 자유롭게 적어주세요." class="${INPUT} resize-none">${fv('concept')}</textarea>`)}
${field('요청사항',`<textarea id="f_note" rows="2" placeholder="기타 요청사항" class="${INPUT} resize-none">${fv('note')}</textarea>`)}
${field('자료 파일 업로드 (선택)',uploadZone("f_files","제품 이미지·영상·가이드·레퍼런스 등 (여러 개 가능)"))}
${S.cust?"":field('사업자등록증 첨부 (필수)',`<input type="file" id="f_bizcert" accept=".pdf,.jpg,.jpeg,.png" class="block w-full text-[14px] text-g600 file:mr-3 file:py-2.5 file:px-4 file:rounded-xl file:border-0 file:bg-blue-tint file:text-blue file:font-bold file:cursor-pointer"><p class="text-[12px] text-g400 mt-1">신규 신청 시 필수입니다. 이미 가입된 회원·파트너사는 첨부 없이 신청할 수 있습니다.</p>`)}
<div class="pt-2 border-t border-g100 mt-2"><p class="text-[15px] font-medium text-g900 mb-2.5 mt-3">필수 동의 항목</p>
<label class="flex items-center gap-2.5 cursor-pointer py-1"><input type="checkbox" id="f_agree3" ${S.form.agree3?'checked':''} class="w-5 h-5 rounded accent-blue flex-shrink-0"><span class="text-[15px] text-g900 flex-1">콘텐츠 2차 활용 동의 <span class="text-g400 font-bold">(선택)</span></span></label><label class="flex items-center gap-2.5 cursor-pointer py-1"><input type="checkbox" id="f_agree1" ${S.form.agree1?'checked':''} class="w-5 h-5 rounded accent-blue flex-shrink-0"><span class="text-[15px] text-g900 flex-1">이용약관 동의 <span class="text-blue font-bold">(필수)</span></span><button type="button" onclick="openLegal('terms')" class="text-[14px] text-g500 underline">내용 보기</button></label>
<label class="flex items-center gap-2.5 cursor-pointer py-1"><input type="checkbox" id="f_agree2" ${S.form.agree2?'checked':''} class="w-5 h-5 rounded accent-blue flex-shrink-0"><span class="text-[15px] text-g900 flex-1">개인정보 수집 및 이용 동의 <span class="text-blue font-bold">(필수)</span></span><button type="button" onclick="openLegal('privacy')" class="text-[14px] text-g500 underline">내용 보기</button></label></div>
</div>`;}
const NOTICE=`<div class="bg-blue-soft rounded-[20px] p-5 mb-6"><p class="text-[16.5px] font-bold text-g900 mb-3" style="word-break:keep-all">신청하시면 캠페인 관리가 이렇게 간편해집니다</p><div class="flex flex-wrap items-center gap-x-1 gap-y-2 mb-3.5"><span class="inline-flex items-center gap-1 bg-white rounded-full pl-1 pr-2 py-1 text-[12px] font-bold text-g800 whitespace-nowrap flex-shrink-0" style="box-shadow:0 1px 3px rgba(17,24,39,.07)"><span class="w-[18px] h-[18px] rounded-full bg-blue text-white text-[10.5px] grid place-items-center flex-shrink-0">1</span>신청서 제출</span><span class="text-blue font-bold text-[12px] flex-shrink-0">→</span><span class="inline-flex items-center gap-1 bg-white rounded-full pl-1 pr-2 py-1 text-[12px] font-bold text-g800 whitespace-nowrap flex-shrink-0" style="box-shadow:0 1px 3px rgba(17,24,39,.07)"><span class="w-[18px] h-[18px] rounded-full bg-blue text-white text-[10.5px] grid place-items-center flex-shrink-0">2</span>담당자 신청 내용 확인</span><span class="text-blue font-bold text-[12px] flex-shrink-0">→</span><span class="inline-flex items-center gap-1 bg-white rounded-full pl-1 pr-2 py-1 text-[12px] font-bold text-g800 whitespace-nowrap flex-shrink-0" style="box-shadow:0 1px 3px rgba(17,24,39,.07)"><span class="w-[18px] h-[18px] rounded-full bg-blue text-white text-[10.5px] grid place-items-center flex-shrink-0">3</span>고객 계정 생성 및 로그인 정보 이메일 발송</span><span class="text-blue font-bold text-[12px] flex-shrink-0">→</span><span class="inline-flex items-center gap-1 bg-white rounded-full pl-1 pr-2 py-1 text-[12px] font-bold text-g800 whitespace-nowrap flex-shrink-0" style="box-shadow:0 1px 3px rgba(17,24,39,.07)"><span class="w-[18px] h-[18px] rounded-full bg-blue text-white text-[10.5px] grid place-items-center flex-shrink-0">4</span>캠페인 관리 페이지 이용</span></div><div class="text-[15px] text-g800 leading-relaxed"><p class="mb-2" style="word-break:keep-all">신청서를 제출해주시면 담당자가 캠페인 내용과 채널 일정을 확인한 뒤 안내드립니다.</p><p class="mb-2" style="word-break:keep-all">진행이 가능한 캠페인의 경우 고객 계정이 생성되며, 로그인 정보는 입력하신 이메일로 발송됩니다.</p><p class="mb-2" style="word-break:keep-all">이후 캠페인 관리 페이지에서 자료 업로드, 업로드 전 확인 요청, 업로드 일정, 진행 결과 리포트를 한 곳에서 확인하실 수 있습니다.</p><p class="text-g500" style="word-break:keep-all">캠페인 일정, 희망 채널, 소재 내용에 따라 진행 가능 여부와 업로드 일정은 달라질 수 있습니다.</p></div></div>`;
function viewApply(){
return `<div class="min-h-screen">${topbar()}
<div class="max-w-2xl mx-auto px-5 py-8 fade-up">
<div class="${CARD} overflow-hidden">
<div class="px-6 md:px-8 py-3 border-b border-g100 flex items-center gap-3">${logoMark('w-11 h-11')}<div><p class="text-[18px] font-bold text-g900">크놀AD 캠페인 신청서</p></div><button onclick="toggleConsult()" class="ml-auto inline-flex items-center gap-1.5 text-[14px] font-bold text-blue bg-blue-soft hover:opacity-80 px-3.5 py-2 rounded-xl whitespace-nowrap">채팅 문의하기</button></div>
<div class="px-6 md:px-8 pt-3.5 pb-7">${NOTICE}${applyFields()}<button onclick="submitApply()" class="${BTN} w-full py-4 mt-6">캠페인 신청하기</button></div></div>
</div>${siteFooter()}</div>`;}

function selectedSummary(){
  if(SEL.size===0)return "";
  const items=[...SEL].map(id=>{const c=CH.find(x=>x.id===id);const q=QSEL[id]||{p:0,b:0};const sub=q.p*pxOf(c).prod+q.b*pxOf(c).pub;const parts=[];if(q.p)parts.push("제작+발행 ×"+q.p);if(q.b)parts.push("단순발행 ×"+q.b);
    return `<div class="flex items-center gap-3 bg-g50 rounded-[20px] p-3">${logoEl(c,"w-10 h-10 text-base")}<div class="flex-1 min-w-0"><p class="font-bold text-g900 truncate">${esc(c.name)}</p><p class="text-[13px] text-g500">${parts.join(" · ")}</p></div><span class="num text-blue font-bold text-[15px] flex-shrink-0">${wonM(sub)}</span><button onclick="togglePick('${c.id}')" class="w-7 h-7 rounded-full bg-g200 text-g500 grid place-items-center hover:bg-red-100 hover:text-red-500 flex-shrink-0"><i data-lucide="x" class="w-4 h-4"></i></button></div>`;}).join("");
  return `<div class="space-y-2">${items}</div><div class="flex justify-between items-center pt-5 mt-5 border-t border-g100"><span class="text-[16px] font-bold text-g600">합계 (VAT 별도)</span><span class="text-[20px] font-bold text-blue num">${wonM(selTotal())}</span></div>`;
}
function filteredCH(){const m={"국내":"KR","일본":"JP","미국":"US"};return CH.filter(c=>(_region==="전체"||c.region===m[_region])&&(c.name.includes(_search)||(c.read&&c.read.includes(_search))));}
function selTotal(){let t=0;SEL.forEach(id=>{const c=CH.find(x=>x.id===id);const q=QSEL[id]||{p:0,b:0};t+=q.p*pxOf(c).prod+q.b*pxOf(c).pub;});return t;}
function pickRow(c,i){const q=QSEL[c.id]||{p:0,b:0};const sel=(q.p+q.b)>0;
const subs=[`<div class="flex items-center justify-between gap-3"><span class="inline-flex items-center gap-1.5 text-[12px] text-g500"><span class="w-1.5 h-1.5 rounded-full bg-red-500"></span>YouTube</span><span class="font-bold text-g900 num text-[14px]">${fmtSub(c.yt)}</span></div>`];
if(c.ig)subs.push(`<div class="flex items-center justify-between gap-3"><span class="inline-flex items-center gap-1.5 text-[12px] text-g400"><span class="w-1.5 h-1.5 rounded-full bg-pink-500"></span>Instagram</span><span class="font-bold text-g600 num text-[13px]">${c.ig}</span></div>`);
if(c.tt)subs.push(`<div class="flex items-center justify-between gap-3"><span class="inline-flex items-center gap-1.5 text-[12px] text-g400"><span class="w-1.5 h-1.5 rounded-full bg-g800"></span>TikTok</span><span class="font-bold text-g600 num text-[13px]">${c.tt}</span></div>`);
return `<tr class="border-b border-g100 last:border-0 ${sel?'bg-blue-soft':''}">
<td class="px-4 py-4 text-[14px] text-g300 num align-middle font-bold">${String(i+1).padStart(2,"0")}</td>
<td class="px-4 py-4 align-middle"><div class="flex items-center gap-3">${logoEl(c,"w-12 h-12 text-base")}<div class="min-w-0"><div class="flex items-center gap-1.5"><p class="font-bold text-g900 truncate text-[16px]">${esc(c.name)}</p>${c.featured?'<span class="text-blue text-xs">★</span>':''}${c.isNew?'<span class="text-[10px] font-bold text-emerald-600 bg-emerald-50 px-1 rounded">NEW</span>':''}</div>${c.read?`<p class="text-[13px] text-g400 truncate">${esc(c.read)}</p>`:''}<a href="https://www.youtube.com/@${encodeURIComponent(c.handle)}" target="_blank" rel="noreferrer" onclick="event.stopPropagation()" class="text-[12px] text-blue font-bold inline-flex items-center gap-0.5">채널 보기 ↗</a></div></div></td>
<td class="px-4 py-4 align-middle"><div class="flex gap-1 flex-wrap">${c.plat.map(platBadge).join("")}</div></td>
<td class="px-4 py-4 align-middle"><div class="space-y-1.5 min-w-[150px]">${subs.join("")}</div></td>
<td class="px-4 py-4 align-middle"><p class="text-[17px] font-bold text-g900 num leading-none">${fmtView(c.views)}</p><p class="text-[11px] text-g400 mt-1">총 조회수</p></td>
<td class="px-4 py-4 align-middle"><span class="text-[13px] font-bold text-g500 bg-g100 px-2 py-1 rounded-lg">${REGION_LABEL[c.region]}</span></td>
<td class="px-4 py-4 align-middle"><p class="text-[15px] font-bold text-blue num text-center">${pxOf(c).prod}만 원</p><div class="flex items-center justify-center gap-1 mt-1.5"><button onclick="incQ('${c.id}','p',-1)" class="w-6 h-6 rounded-lg bg-g100 grid place-items-center font-bold text-g600 hover:bg-g200">−</button><span class="num w-5 text-center text-[15px] font-bold ${q.p>0?'text-blue':'text-g300'}">${q.p}</span><button onclick="incQ('${c.id}','p',1)" class="w-6 h-6 rounded-lg bg-g100 grid place-items-center font-bold text-g600 hover:bg-g200">+</button></div></td>
<td class="px-4 py-4 align-middle"><p class="text-[15px] font-bold text-g900 num text-center">${pxOf(c).pub}만 원</p><div class="flex items-center justify-center gap-1 mt-1.5"><button onclick="incQ('${c.id}','b',-1)" class="w-6 h-6 rounded-lg bg-g100 grid place-items-center font-bold text-g600 hover:bg-g200">−</button><span class="num w-5 text-center text-[15px] font-bold ${q.b>0?'text-blue':'text-g300'}">${q.b}</span><button onclick="incQ('${c.id}','b',1)" class="w-6 h-6 rounded-lg bg-g100 grid place-items-center font-bold text-g600 hover:bg-g200">+</button></div></td>
<td class="px-4 py-4 align-middle text-center"><div class="cbx w-6 h-6 rounded-full grid place-items-center mx-auto ${sel?'bg-blue':'border-2 border-g300 bg-white'}">${sel?'<i data-lucide="check" class="w-3.5 h-3.5 text-white pop"></i>':''}</div></td></tr>`;}
function channelTableBlock(){const l=filteredCH();
return `<div class="bg-blue-soft rounded-2xl px-4 py-3 text-[14px] text-g700 mb-4 flex items-start gap-2"><i data-lucide="info" class="w-4 h-4 text-blue mt-0.5 flex-shrink-0"></i>유튜브 채널에 업로드 시 인스타그램·틱톡에도 미러링으로 함께 업로드됩니다. 인스타그램 또는 틱톡 계정을 운영하지 않는 채널의 경우, 다른 보유 채널을 통해 콘텐츠가 랜덤으로 업로드됩니다.</div>
<div class="flex items-center gap-3 mb-4 flex-wrap">
<div class="flex gap-2" id="pickChips">${["전체","국내","일본","미국"].map(r=>`<button onclick="setRegion('${r}')" class="px-4 py-2 rounded-2xl text-[14px] font-bold transition-all ${_region===r?'bg-blue text-white':'bg-white border border-g200 text-g600 hover:bg-g100'}">${r}</button>`).join("")}</div>
<div class="relative flex-1 min-w-[200px] max-w-sm"><i data-lucide="search" class="w-4 h-4 absolute left-4 top-1/2 -translate-y-1/2 text-g400"></i><input oninput="onSearch(this.value)" value="${esc(_search)}" class="w-full pl-11 pr-4 py-2.5 rounded-2xl text-[15px] bg-white border border-g200 placeholder:text-g500 focus:outline-none focus:border-blue/40" placeholder="채널명 검색"></div>
<span class="ml-auto text-[14px] text-g400 font-medium" id="pickCount">${l.length}개 채널</span></div>
<div class="${CARD} overflow-hidden"><div class="overflow-x-auto"><table class="w-full text-left min-w-[1060px]">
<thead><tr class="border-b border-g200 bg-g50">${["NO","채널명","플랫폼","구독자 / 팔로워","총 조회수","지역","제작+발행","단순발행","선택"].map(h=>`<th class="px-4 py-3 text-[13px] font-bold text-g500 whitespace-nowrap">${h}</th>`).join("")}</tr></thead>
<tbody id="pickRows">${l.map(pickRow).join("")}</tbody></table></div></div>`;}
function viewPicker(){
return `<div class="min-h-screen bg-g50 pb-12">
<div class="sticky top-0 z-40 bg-white border-b border-g100"><div class="max-w-7xl mx-auto px-6 py-3 flex items-center gap-3">
<button onclick="finishPicker()" class="w-10 h-10 rounded-2xl bg-g100 grid place-items-center hover:bg-g200 flex-shrink-0"><i data-lucide="arrow-left" class="w-4 h-4 text-g700"></i></button>
<div class="min-w-0"><p class="text-[20px] font-bold text-g900 leading-none">채널 선택</p><p class="text-[14px] text-g500 mt-1 truncate">원하는 채널을 선택해주세요 (복수 선택 가능)</p></div>
<div class="ml-auto flex items-center gap-6 flex-shrink-0"><span id="selTotal" class="text-blue num" style="font-weight:800;font-size:clamp(26px,4vw,40px)">${wonM(selTotal())}</span><div class="text-right"><p class="text-[13px] text-g500 mb-1.5">선택 <span id="selCnt">${SEL.size}</span>개 · 합계 (VAT 별도)</p><button onclick="finishPicker()" class="${BTN} px-7">선택 완료 →</button></div></div></div></div>
<div class="max-w-7xl mx-auto px-6 pt-6">${channelTableBlock()}</div></div>`;}
function isSimpleWf(c){try{var ch=(c&&c.channels)||[];if(typeof ch==="string")ch=JSON.parse(ch);if(!ch||!ch.length)return false;var hasPub=false;for(var i=0;i<ch.length;i++){if((ch[i].prodQty||0)>0)return false;if((ch[i].pubQty||0)>0)hasPub=true;}return hasPub;}catch(e){return false;}}
function togglePick(id){if(SEL.has(id)){SEL.delete(id);delete QSEL[id];}else{SEL.add(id);var _bm=false,_tk;for(_tk in QSEL){if((QSEL[_tk]||{}).b>0){_bm=true;break}}QSEL[id]=_bm?{p:0,b:1}:{p:1,b:0};}applyChange();}
function incQ(id,t,d){if(d>0){var _m=null,_k;for(_k in QSEL){if((QSEL[_k]||{}).p>0){_m="p";break}}if(!_m){for(_k in QSEL){if((QSEL[_k]||{}).b>0){_m="b";break}}}if(t==="p"&&_m==="b"){toast("단순업로드(단순발행)와 제작+발행은 한 신청서에 함께 담을 수 없습니다");return;}if(t==="b"&&_m==="p"){toast("제작+발행과 단순업로드(단순발행)는 한 신청서에 함께 담을 수 없습니다");return;}}var q=QSEL[id]||{p:0,b:0};q[t]=Math.max(0,Math.min(99,(q[t]||0)+d));QSEL[id]={p:q.p||0,b:q.b||0};if(((QSEL[id].p)+(QSEL[id].b))<=0){SEL.delete(id);delete QSEL[id];}else{SEL.add(id);}applyChange();}
function setPickProduct(id,p){PROD[id]=p;applyChange();}
function applyChange(){const r=document.getElementById("pickRows");if(r)updateTable();const sc=document.getElementById("selCnt");if(sc)sc.textContent=SEL.size;const st=document.getElementById("selTotal");if(st)st.textContent=wonM(selTotal());const box=document.getElementById("selBox");if(box)box.innerHTML=selectedSummary();if(window.lucide)lucide.createIcons();}
function updateTable(){const l=filteredCH();const r=document.getElementById("pickRows");if(r)r.innerHTML=l.length?l.map(pickRow).join(""):`<tr><td colspan="9" class="text-center py-12 text-g400 text-sm">검색 결과가 없습니다.</td></tr>`;const c=document.getElementById("pickCount");if(c)c.textContent=l.length+"개 채널";if(window.lucide)lucide.createIcons();}
function onSearch(v){_search=v;updateTable();}
function setRegion(r){_region=r;updateTable();const ch=document.getElementById("pickChips");if(ch)ch.querySelectorAll("button").forEach(b=>{const on=b.textContent.trim()===r;b.className=`px-4 py-2 rounded-2xl text-[14px] font-bold transition-all ${on?'bg-blue text-white':'bg-white border border-g200 text-g600 hover:bg-g100'}`;});}
function openPicker(){saveForm();if(S.role==="customer"){S._pickFrom="cust-apply";go("cust-channels",true);}else{S._cameFrom="apply";go("channel-picker");}}
function finishPicker(){if(S.role==="customer"){var b=S._pickFrom||"customer-dashboard";S._pickFrom=null;go(b);}else{go(S._cameFrom||"apply");}}
function notifyEmail(to,subject,html){try{if(!to)return;fetch(SUPA_URL+"/functions/v1/notify-email",{method:"POST",headers:Object.assign({"Content-Type":"application/json"},SH),body:JSON.stringify({to:to,subject:subject,html:html})}).catch(function(){});}catch(e){}}
function emailTpl(a,title,body){var brand=(a&&(a.brand_name||a.brand))||"";var nm=(a&&a.name)||"고객";var t2=String(title).replace("[크놀AD] ","");return '<div style="max-width:520px;margin:0 auto;font-family:Apple SD Gothic Neo,Malgun Gothic,sans-serif;color:#191F28"><div style="text-align:center;padding:24px 0"><span style="font-size:22px;font-weight:800;color:#2F80ED">크놀AD</span></div><div style="background:#F7F9FC;border-radius:16px;padding:28px"><h2 style="font-size:18px;margin:0 0 12px">'+t2+'</h2><p style="font-size:15px;line-height:1.7;color:#333;margin:0 0 16px">'+nm+'님, 안녕하세요.<br>'+body+'</p>'+(brand?'<p style="font-size:13px;color:#8B95A1;margin:0">캠페인: '+brand+'</p>':'')+'<div style="margin-top:20px"><a href="https://www.cnolad.com" style="display:inline-block;background:#2F80ED;color:#fff;text-decoration:none;padding:11px 22px;border-radius:10px;font-weight:700;font-size:14px">사이트에서 확인하기</a></div></div><p style="text-align:center;font-size:12px;color:#B0B8C1;margin-top:16px">본 메일은 발신 전용입니다 · 크놀AD</p></div>';}
function notifyTelegram(t){try{fetch(SUPA_URL+"/functions/v1/notify-telegram",{method:"POST",headers:Object.assign({"Content-Type":"application/json"},SH),body:JSON.stringify({text:t})}).catch(function(){});}catch(e){}}
function submitApply(){saveForm();const f=S.form;var _isP=(S.cust&&S.cust.role==="파트너사");if(_isP){if(!f.manager||!f.manager.trim()||!f.email||!f.email.trim()||!f.brand||!f.brand.trim()){toast("필수: 담당자·이메일·브랜드명을 입력해주세요");return;}f.name=f.manager;}else if(!f.name||!f.name.trim()||!f.email||!f.email.trim()||!f.phone||!f.phone.trim()||!f.brand||!f.brand.trim()){toast("필수: 담당자명·이메일·연락처·브랜드명을 모두 입력해주세요");return;}
  if(!f.agree1||!f.agree2){toast("필수 동의 항목(이용약관·개인정보)에 동의해주세요");return;}
  var _bz=document.getElementById("f_bizcert");var _hasBiz=_bz&&_bz.files&&_bz.files.length;
  if(!S.cust&&S.role!=="admin"&&S.role!=="cs"&&!_hasBiz&&!S._bizOk){fetch(SUPA_URL+"/rest/v1/knollad_members?email=eq."+encodeURIComponent(f.email.toLowerCase())+"&select=email&limit=1",{headers:SH}).then(function(r){return r.json();}).then(function(rows){if(rows&&rows[0]){S._bizOk=true;submitApply();}else{toast("사업자등록증을 첨부해주세요 (신규 신청 필수)");}}).catch(function(){toast("사업자등록증을 첨부해주세요 (신규 신청 필수)");});return;}
  const chans=[...SEL].map(id=>{const c=CH.find(x=>x.id===id),q=QSEL[id]||{p:1,b:0};return {id:c.id,name:c.name,prodQty:q.p,pubQty:q.b,prod_price:pxOf(c).prod,pub_price:pxOf(c).pub,qty:q.p+q.b,amount:q.p*pxOf(c).prod+q.b*pxOf(c).pub,price:q.p*pxOf(c).prod+q.b*pxOf(c).pub,product:(q.p&&q.b)?('제작+발행×'+q.p+' / 단순발행×'+q.b):(q.p?('제작+발행×'+q.p):('단순발행×'+q.b))};});
  S._submitted={brand:f.brand,email:f.email.toLowerCase(),channels:[...SEL].map(id=>({c:CH.find(x=>x.id===id),q:QSEL[id]||{p:1,b:0}})),total:selTotal()};
  const send=function(files){const payload={contact_name:f.name,email:f.email.toLowerCase(),phone:f.phone,brand_name:f.brand,preferred_date:f.date||null,product_link:f.link||null,material:f.material||null,ad_disclosure:f.ad||null,concept:f.concept||null,note:f.note||null,manager:f.manager||null,channels:chans,total_amount:selTotal(),files:(files&&files.length)?files:null,biz_reg:(S._bizUrl||null)};try{notifyTelegram("📝 [캠페인 신청] "+((f.brand)||"")+" — "+((f.name||f.manager||f.email)||"고객"));}catch(_te){}
    fetch(SUPA_URL+"/rest/v1/knollad_applications",{method:"POST",headers:Object.assign({"Content-Type":"application/json","Prefer":"return=minimal"},SH),body:JSON.stringify(payload)}).then(r=>{if(!r.ok)console.warn("supabase",r.status);}).catch(e=>console.warn(e));
    if(S.role==="customer"){toast("추가 캠페인 신청이 접수되었습니다");SEL=new Set();PROD={};QSEL={};go("customer-dashboard");}else{go("apply-success");}};
  const _fb=document.getElementById("f_files");const fi=_fb?_fb.parentElement.querySelector('input[type="file"]'):null;
  const _goSend=function(){if(fi&&fi.files&&fi.files.length){toast("자료 파일 업로드 중…");uploadFilesAll(fi.files,function(arr){send(arr);});}else send(null);};
  S._bizUrl=null;var _bz2=document.getElementById("f_bizcert");
  if(_bz2&&_bz2.files&&_bz2.files.length){toast("사업자등록증 업로드 중…");uploadFilesAll([_bz2.files[0]],function(a2){S._bizUrl=(a2&&a2[0]&&a2[0].url)||null;_goSend();});}else _goSend();}
function uploadFilesAll(files,cb){var arr=[];var n=files.length;var done=0;if(!n){cb([]);return;}for(var i=0;i<n;i++){(function(file){var path=Date.now()+"_"+Math.random().toString(36).slice(2,6)+"_"+((file.name||"file").replace(/[^\w.\-]/g,"_"));fetch(SUPA_URL+"/storage/v1/object/deliverables/"+encodeURIComponent(path),{method:"POST",headers:{apikey:SUPA_KEY,Authorization:"Bearer "+SUPA_KEY,"Content-Type":file.type||"application/octet-stream","x-upsert":"true"},body:file}).then(function(r){if(r.ok)arr.push({name:file.name,url:SUPA_URL+"/storage/v1/object/public/deliverables/"+encodeURIComponent(path)});done++;if(done===n)cb(arr);}).catch(function(){done++;if(done===n)cb(arr);});})(files[i]);}}
function viewApplySuccess(){const sub=S._submitted;
const rows=sub&&sub.channels.length?`<div class="mt-5 space-y-2">${sub.channels.map(x=>{var q=x.q||{p:1,b:0};var amt=q.p*pxOf(x.c).prod+q.b*pxOf(x.c).pub;var parts=[];if(q.p)parts.push("제작+발행 ×"+q.p);if(q.b)parts.push("단순발행 ×"+q.b);return `<div class="flex items-center gap-3 bg-g50 rounded-[20px] p-3">${logoEl(x.c,"w-10 h-10 text-base")}<div class="flex-1 text-left"><p class="text-[15px] font-bold text-g900">${esc(x.c.name)}</p><p class="text-[13px] text-g400">${parts.join(" · ")}</p></div><p class="text-[15px] font-bold text-g900 num">${wonM(amt)}</p></div>`;}).join("")}<div class="flex justify-between items-center pt-3 px-1"><span class="text-[15px] font-bold text-g600">합계 (VAT 별도)</span><span class="text-[19px] font-bold text-blue num">${wonM(sub.total)}</span></div></div>`:"";
return `<div class="min-h-screen bg-g50 flex items-center justify-center px-6 py-16"><div class="max-w-md w-full fade-up"><div class="${CARD} p-8 text-center">
<div class="w-16 h-16 rounded-full bg-blue-tint flex items-center justify-center mx-auto mb-6"><i data-lucide="check" class="w-8 h-8 text-blue"></i></div>
<h1 class="text-[26px] font-bold text-g900 mb-1.5">신청이 접수되었어요</h1><p class="text-[16px] text-g500">${sub?esc(sub.brand)+' 캠페인':'크놀AD 캠페인'} 신청이 정상 접수되었습니다.</p>
<div class="inline-flex items-center gap-2 px-3 py-1.5 rounded-full bg-amber-50 mt-4"><span class="w-1.5 h-1.5 rounded-full bg-amber-400"></span><span class="text-[14px] font-bold text-amber-700">검토 대기중</span></div>${rows}
<div class="mt-7 text-left bg-g50 rounded-[20px] p-4 text-[15px] text-g600 leading-relaxed">승인 완료 시 입력하신 이메일(${sub?esc(sub.email):'이메일'})을 아이디로 계정이 발급되고 비밀번호가 안내됩니다. ‘로그인’에서 로그인 후 진행 상태를 확인하세요.</div>
<button onclick="goHome()" class="${BTN_GHOST} w-full mt-5">홈으로 돌아가기</button></div></div></div>`;}

/* ===== 로그인 ===== */
function viewLogin(){return `<div class="min-h-screen flex items-center justify-center px-6 py-12" style="background:radial-gradient(circle at 50% -10%,rgba(49,130,246,.14),transparent 55%),#F4F7FC">
<div class="w-full max-w-md fade-up">
<button onclick="goHome()" class="text-g500 hover:text-g800 mb-5" style="font-size:14px;font-weight:600">← 홈으로</button>
<div class="${CARD} p-8 md:p-9">
<div class="text-center mb-7"><div class="w-16 h-16 rounded-2xl bg-blue-soft flex items-center justify-center mx-auto mb-4">${logoMark('w-11 h-11')}</div><h1 class="text-g900" style="font-size:27px;font-weight:800">크놀AD 로그인</h1><p class="text-g500 mt-1.5" style="font-size:15px">승인된 고객 · 관리자 전용 공간입니다</p></div>
<div class="space-y-4">${field('아이디 (이메일)',`<input id="loginEmail" type="text" placeholder="name@company.com" class="${INPUT}">`)}${field('비밀번호',`<input id="loginPw" type="password" placeholder="발급받은 비밀번호" class="${INPUT}" onkeydown="if(event.key==='Enter')doLogin()">`)}<button onclick="doLogin()" id="loginBtn" class="${BTN} w-full cta-lift" style="margin-top:4px">로그인 →</button></div>
<div class="mt-6 p-4 rounded-2xl" style="background:#EEF4FF;border:1px solid #DCE7FF"><p style="font-size:13px;color:#1B64DA;line-height:1.6">관리자 승인 후 발급받은 이메일·비밀번호로 로그인하세요. 승인 전에는 로그인할 수 없습니다.</p></div>
</div>
<button onclick="newApply()" class="w-full text-center mt-5 text-g500 hover:text-g800" style="font-size:14px">아직 신청 전이신가요? <span class="text-blue" style="font-weight:700">캠페인 신청하기 →</span></button>
</div></div>`;}
function doLogin(){const e=(gv("loginEmail")||"").trim().toLowerCase();const pw=gv("loginPw")||"";
  if(e==="admin"){if(pw==="admin123"){S.role="admin";try{localStorage.setItem("knollad_sess",JSON.stringify({role:"admin"}));}catch(_e){}logEvent("login");go("admin-dashboard");}else toast("관리자 비밀번호가 올바르지 않습니다");return;}
  if(e==="cnolcs1"){if(pw==="cnolcs123"){S.role="cs";try{localStorage.setItem("knollad_sess",JSON.stringify({role:"cs"}));}catch(_e){}logEvent("login");go("admin-dashboard");}else toast("CS 비밀번호가 올바르지 않습니다");return;}
  if(!e||!pw){toast("아이디와 비밀번호를 입력해주세요");return;}
  const btn=document.getElementById("loginBtn");if(btn)btn.textContent="확인 중…";
  fetch(SUPA_URL+"/rest/v1/rpc/knollad_login",{method:"POST",headers:Object.assign({"Content-Type":"application/json"},SH),body:JSON.stringify({p_email:e,p_password:pw})})
  .then(r=>r.json()).then(rows=>{if(Array.isArray(rows)&&rows.length){if((rows[0].role||"")==="관리자"){S.role="admin";try{localStorage.setItem("knollad_sess",JSON.stringify({role:"admin"}));}catch(_e){}logEvent("login");go("admin-dashboard");return;}S.role="customer";S.cust={email:e,brand:rows[0].brand_name,name:rows[0].contact_name,role:rows[0].role||"일반회원"};S.wf={step:1,edit:null};S.activeCamp=null;S.myCamps=[];try{localStorage.setItem("knollad_sess",JSON.stringify({role:"customer",cust:S.cust}));}catch(_e){}logEvent("login");go("customer-dashboard");}else{if(btn)btn.textContent="로그인";toast("승인된 계정이 아니거나 정보가 일치하지 않습니다");}})
  .catch(()=>{if(btn)btn.textContent="로그인";toast("로그인 오류. 잠시 후 다시 시도해주세요");});}

/* ===== SHELLS ===== */
function sidebar(items,cur,badge,bell,bellT){return `<aside class="w-56 border-r border-g100 flex flex-col fixed top-0 bottom-0 z-20 bg-white"><div class="px-5 py-5"><div class="flex items-center justify-between">${brandLogo(true,true)}${bellT?`<button onclick="openTodo()" class="flex items-center gap-1.5 pl-2.5 pr-3 h-10 rounded-full ${bell>0?"bg-red-50":"bg-g100"} hover:opacity-90"><i data-lucide="bell" class="w-[20px] h-[20px] ${bell>0?"text-red-500":"text-g600"}"></i>${bell>0?`<span class="text-[14px] font-bold" style="color:#EF4444">${bell>99?"99+":bell}</span>`:""}</button>`:""}</div>${badge?`<span class="mt-2 inline-flex px-2 py-0.5 rounded-md bg-blue-tint text-blue text-[11px] font-bold">${badge}</span>`:""}</div><nav class="flex-1 px-3 space-y-1 overflow-y-auto">${items.map(it=>{const a=cur===it.id;return `<button onclick="${it.act||("go('"+it.id+"')")}" class="w-full flex items-center gap-3 px-3 py-2.5 rounded-2xl text-[15px] font-bold ${a?'bg-blue-tint text-blue':'text-g500 hover:text-g800 hover:bg-g100'}"><i data-lucide="${it.icon}" class="w-[16px] h-[16px]"></i><span class="flex-1 text-left">${it.label}</span>${it.dot?'<span class="inline-flex items-center justify-center text-[10px] font-bold rounded-full w-4 h-4" style="background:#EF4444;color:#fff">N</span>':''}</button>`;}).join("")}</nav><div class="px-3 py-3 border-t border-g100"><button onclick="logout()" class="w-full flex items-center gap-3 px-3 py-2.5 rounded-2xl text-[15px] font-bold text-g500 hover:text-g800 hover:bg-g100"><i data-lucide="log-out" class="w-[16px] h-[16px]"></i>로그아웃</button></div></aside>`;}
function customerShell(v){if(S.cust&&!(S.myCampsAll||[]).length)setTimeout(loadMyCamps,30);const items=[{id:"todo",label:"해야 할 일",icon:"list-todo"},{id:"customer-dashboard",label:"캠페인 관리",icon:"layout-dashboard"},{id:"workflow",label:"워크플로우",icon:"list-checks"},{id:"calendar",label:"캠페인 일정",icon:"calendar"},{id:"cust-apply",label:"캠페인 추가 신청",icon:"plus-circle",act:"newApply()"},{id:"cust-channels",label:"채널 리스트",icon:"layers"},{id:"notes",label:"메신저",icon:"message-circle"},{id:"report",label:"리포트",icon:"bar-chart-3"},{id:"guide",label:"가이드라인",icon:"book-open"},{id:"settlement",label:"정산",icon:"receipt"},{id:"mypage",label:"마이페이지",icon:"user"}];
let b;if(v==="cust-channels")b=custChannels();else if(v==="cust-apply")b=custApply();else if(v==="workflow")b=viewWorkflow();else if(v==="calendar")b=viewCalendar();else if(v==="notes")b=viewNotes();else if(v==="todo")b=viewTodo();else if(v==="settlement")b=viewSettlement();else if(v==="mypage")b=viewMyPage();else if(v==="report")b=viewReport();else if(v==="guide")b=viewGuide();else b=viewCustomerDashboard();
const ua=S.activeCamp?unreadCount(S.activeCamp,"cust"):0;const bell=buildTasks().length;
items.forEach(function(it){if(it.id==="workflow")it.dot=wfPending(S.activeCamp)||ua>0;if(it.id==="notes")it.dot=ua>0;if(it.id==="todo")it.dot=bell>0;});
return `<div class="flex min-h-screen bg-g50">${sidebar(items,v,null,bell,true)}<main class="flex-1 ml-56 min-h-screen">${mgrBar()}${b}</main></div>`;}
function adminShell(v){if(!(ADM_ROWS||[]).length)setTimeout(loadApps,30);const items=[{id:"admin-todo",label:"해야 할 일",icon:"list-todo"},{id:"admin-dashboard",label:"캠페인 관리",icon:"clipboard-list"},{id:"admin-workflow",label:"워크플로우 관리",icon:"list-checks"},{id:"admin-calendar",label:"캠페인 일정",icon:"calendar"},{id:"admin-sales",label:"매출분석",icon:"trending-up"},{id:"admin-members",label:"회원DB",icon:"users"},{id:"admin-channels",label:"채널 DB",icon:"layers"},{id:"admin-guide",label:"가이드라인",icon:"book-open"},{id:"admin-consults",label:"실시간 상담",icon:"message-circle"},{id:"telegram-alert",label:"텔레그램 알림",icon:"send",act:"window.open('https://t.me/+wqI8pKCnupI5YjY9','_blank')"}];if(S.role==="cs"){for(var _ci=items.length-1;_ci>=0;_ci--){if(items[_ci].id==="admin-sales"||items[_ci].id==="admin-members"||items[_ci].id==="admin-channels")items.splice(_ci,1);}if(v==="admin-sales"||v==="admin-members"||v==="admin-channels"){v="admin-dashboard";S.view="admin-dashboard";}}let b=v==="admin-consults"?viewAdminConsults():v==="admin-members"?viewAdminMembers():v==="admin-channels"?viewAdminChannels():v==="admin-workflow"?viewAdminWorkflow():v==="admin-calendar"?viewAdminCalendar():v==="admin-sales"?viewAdminSales():v==="admin-todo"?viewTodo():v==="admin-guide"?viewGuide():viewAdminList();
const bell=buildTasks().length;
items.forEach(function(it){if(it.id==="admin-todo")it.dot=bell>0;if(it.id==="admin-dashboard")it.dot=(ADM_ROWS||[]).some(function(c){return !campSeen(c.id);});if(it.id==="admin-workflow")it.dot=(ADM_ROWS||[]).some(function(c){return c.status==="승인 완료"&&unreadCount(c,"adm")>0;});if(it.id==="admin-consults")it.dot=(S.consults||[]).some(function(c){var m=c.messages||[];return m.length&&m[m.length-1].role==="cust";});});if(!S.consults)setTimeout(loadConsults,60);
return `<div class="flex min-h-screen bg-g50">${sidebar(items,v,"관리자",bell,true)}<main class="flex-1 ml-56 min-h-screen">${mgrBar()}${b}</main></div>`;}
function custChannels(){return `<div class="p-8 md:p-10">
<div class="flex items-center justify-between mb-6 flex-wrap gap-3"><div><p class="text-[15px] font-bold text-blue mb-2">CHANNELS</p><div class="flex items-center gap-2.5">${S._pickFrom?'<button onclick="finishPicker()" aria-label="뒤로가기" class="w-9 h-9 rounded-xl bg-g100 grid place-items-center hover:bg-g200 flex-shrink-0"><i data-lucide="arrow-left" class="w-4 h-4 text-g700"></i></button>':''}<h1 class="text-[32px] font-bold text-g900 tracking-tight">채널 리스트</h1></div><p class="text-[16px] text-g500 mt-2">원하는 채널을 체크하면 ‘캠페인 추가 신청’에 반영됩니다</p></div><div class="text-right flex-shrink-0"><p class="text-[13px] text-g500 mb-1">선택 <span id="selCnt">${SEL.size}</span>개 · 합계 (VAT 별도)</p><div class="flex items-center gap-6 justify-end"><span id="selTotal" class="text-[30px] text-blue num" style="font-weight:800">${wonM(selTotal())}</span><button onclick="go('cust-apply')" class="${BTN} px-6">선택 완료 →</button></div></div></div>
${channelTableBlock()}</div>`;}
function custApply(){return `<div class="p-8 md:p-10"><div class="max-w-2xl">${pageHeader("CAMPAIGN","캠페인 추가 신청","새 캠페인을 신청하면 동일하게 검토 후 진행됩니다")}
<div class="${CARD} p-6 md:p-8">${NOTICE}${applyFields()}<button onclick="submitApply()" class="${BTN} w-full py-4 mt-6">추가 캠페인 신청하기</button></div></div></div>`;}
const WF=[
{t:"문의 접수 및 상담",d:"단가·일정 안내 및 채널·제작 방향 협의",who:"완료"},
{t:"자료 공유",d:"소재·가이드·레퍼런스 전달 (고객 → 크놀AD)",who:"고객",act:"data"},
{t:"콘티 작성",d:"전달받은 자료로 콘티(기획안) 작성 후 전달 (크놀AD)",who:"크놀AD",act:"adminConti"},
{t:"콘티 컨펌 및 피드백",d:"전달받은 콘티 검토 후 컨펌 또는 수정 요청 (고객)",who:"고객",act:"conti"},
{t:"영상 제작",d:"확정 콘티로 촬영·편집 후 전달 (크놀AD)",who:"크놀AD",act:"adminVideo"},
{t:"영상 컨펌 및 피드백",d:"전달받은 영상 검토 후 컨펌 또는 수정 요청 (고객)",who:"고객",act:"video"}];
function wfPending(c){if(!c)return false;const wf=wfOf(c);const s=wf.step;if(s===2)return true;if(s===4)return !!wf.conti;if(s===6)return !!wf.video;return false;}
function asDeliver(v){if(!v)return null;if(typeof v==="string")return {link:v};return v;}
function unreadCount(camp,role){if(!camp)return 0;try{var seen=JSON.parse(localStorage.getItem("knollad_seen_"+role)||"{}");return Math.max(0,((camp.notes||[]).length)-(seen[camp.id]||0));}catch(e){return 0;}}
function markSeen(camp,role){if(!camp)return;try{var seen=JSON.parse(localStorage.getItem("knollad_seen_"+role)||"{}");seen[camp.id]=(camp.notes||[]).length;localStorage.setItem("knollad_seen_"+role,JSON.stringify(seen));}catch(e){}}
function wfOf(c){return (c&&c.wf)?c.wf:{step:(c&&c.status==="승인 완료")?2:1};}
function activeWf(){return wfOf(S.activeCamp);}
function mgrFilt(list){if(S.mgrFilter===undefined){try{S.mgrFilter=localStorage.getItem("cnol_mgr")||null;}catch(_e){S.mgrFilter=null;}}if(S.cust&&S.cust.role==="파트너사"&&S.mgrFilter){return (list||[]).filter(function(c){return (c.manager||"미지정")===S.mgrFilter;});}return list||[];}function setMgr(m){S.mgrFilter=m||null;try{localStorage.setItem("cnol_mgr",m||"");}catch(_e){}if(S.myCampsAll){S.myCamps=mgrFilt(S.myCampsAll);}S.activeCamp=null;render();}function mgrBar(){if(!(S.cust&&S.cust.role==="파트너사"))return "";var all=S.myCampsAll||[];var mgrs=[];all.forEach(function(c){var m=(c.manager||"미지정");if(mgrs.indexOf(m)<0)mgrs.push(m);});if(mgrs.length<1)return "";function btn(v,label){var on=((v||null)===(S.mgrFilter||null));return `<button onclick="setMgr('${String(v).replace(/'/g,"")}')" class="px-4 py-2 rounded-xl text-[14px] font-bold ${on?"bg-blue text-white shadow":"bg-g100 text-g700"}">${esc(label)}</button>`;}return `<div class="px-8 md:px-10 pt-6"><div class="bg-white border-2 border-blue/30 rounded-2xl p-4 shadow-sm"><div class="flex items-center flex-wrap gap-2 mb-3"><span class="text-[15px] font-bold text-g900">👤 담당자별 보기</span><span class="text-[12px] text-g500">담당자를 누르면 그 담당자 캠페인·할 일만 보여요</span></div><div class="flex flex-wrap items-center gap-2">${btn("","전체")}${mgrs.map(function(m){return btn(m,m);}).join("")}</div></div></div>`;}function loadMyCamps(){if(!S.cust)return;fetch(SUPA_URL+"/rest/v1/knollad_applications?email=eq."+encodeURIComponent(S.cust.email)+"&order=created_at.desc&select=*",{headers:SH}).then(r=>r.json()).then(rows=>{S.myCampsAll=Array.isArray(rows)?rows:[];S.myCamps=mgrFilt(S.myCampsAll);var _had=!!S.activeCamp;if((!S.activeCamp)&&S.myCamps.length){S.activeCamp=S.myCamps.find(a=>a.status==="승인 완료")||S.myCamps[0];}else if(S.activeCamp){const f=S.myCamps.find(a=>String(a.id)===String(S.activeCamp.id));if(f)S.activeCamp=f;}var sig=JSON.stringify((S.myCamps||[]).map(function(a){return [a.id,a.status,a.pay_status,(a.wf||{}).step,(a.wf||{}).conti?1:0,(a.wf||{}).video?1:0,(a.notes||[]).length];}));if(sig!==S._campSig){S._campSig=sig;render();}else{renderMyCamps();}}).catch(()=>{});}
function setActiveCamp(id){const a=(S.myCamps||[]).find(x=>String(x.id)===String(id));if(a){S.activeCamp=a;toast(a.brand_name+" 캠페인 선택됨");render();}}
function campDetail(id){const a=(S.myCamps||[]).find(x=>String(x.id)===String(id));if(!a)return;const ch=(a.channels||[]).map(c=>`${esc(c.name)} · ${c.product||''}${c.price?' '+c.price+'만':''}`).join("<br>")||"-";const row=(k,v)=>`<div class="py-2 border-b border-g100 last:border-0"><p class="text-[13px] text-g400 mb-0.5">${k}</p><div class="text-[15px] text-g800 break-all">${v||'-'}</div></div>`;modal(`<div class="flex items-center justify-between mb-3"><h3 class="text-[19px] font-bold text-g900 break-all">${esc(a.brand_name)} 신청내용</h3><button onclick="closeModal()" class="w-8 h-8 rounded-full bg-g100 grid place-items-center text-g500 flex-shrink-0">✕</button></div><div class="max-h-[74vh] overflow-y-auto">${row("상태",statusBadge(a.status))}${row("업로드 희망일",esc(a.preferred_date||''))}${row("제품 링크",a.product_link?`<a href="${esc(a.product_link)}" target="_blank" class="text-blue underline">${esc(a.product_link)}</a>`:'-')}${row("희망 채널",ch)}${row("활용 소재",esc(a.material||''))}${row("광고 고지 방식",esc(a.ad_disclosure||''))}${row("희망 영상 컨셉",esc(a.concept||''))}${row("요청사항",esc(a.note||''))}${row("금액 (VAT 별도)",`<span class="font-bold text-blue num">${wonM(a.total_amount||0)}</span>`)}</div><div class="flex gap-2 mt-4"><button onclick="setActiveCamp('${a.id}');closeModal();go('workflow')" class="${BTN} flex-1">워크플로우 진행 →</button><button onclick="closeModal()" class="${BTN_GHOST} px-5">닫기</button></div>`,"max-w-2xl");}
function rejBtn(a){if(a.status!=="반려")return"";return '<button data-rid="'+a.id+'" onclick="event.stopPropagation();showRejectReason(this.dataset.rid)" class="text-[12px] font-bold text-red-600 underline ml-1">반려 사유 보기</button>';}function showRejectReason(id){var a=(S.myCampsAll||S.myCamps||[]).find(function(x){return String(x.id)===String(id);});if(!a)return;var reason=a.reject_reason||"등록된 반려 사유가 없습니다.";modal('<div class="flex items-center justify-between mb-3"><h3 class="text-[18px] font-bold text-g900">반려 안내</h3><button onclick="closeModal()" class="w-8 h-8 rounded-full bg-g100 grid place-items-center text-g500">✕</button></div><div class="bg-red-50 border border-red-100 rounded-2xl p-4 mb-3"><p class="text-[13px] font-bold text-red-600 mb-1.5">'+esc(a.brand_name)+' 캠페인이 반려되었습니다</p><p class="text-[15px] text-g800" style="white-space:pre-wrap">'+esc(reason)+'</p></div><button onclick="closeModal()" class="'+BTN+' w-full">확인</button>');}function renderMyCamps(){const el=document.getElementById("myCampWrap");if(!el)return;const cs=S.myCamps||[];if(!cs.length){el.innerHTML='<div class="text-[15px] text-g400 text-center py-8">아직 신청한 캠페인이 없습니다.<br>상단 ‘캠페인 추가 신청’으로 시작하세요.</div>';return;}
el.innerHTML=cs.map(a=>{const on=S.activeCamp&&String(S.activeCamp.id)===String(a.id);return `<div onclick="setActiveCamp('${a.id}')" class="border ${on?'border-blue bg-blue-soft':'border-g100'} rounded-[20px] p-4 flex items-center gap-3 flex-wrap cursor-pointer hover:border-blue/50"><div class="flex-1 min-w-0"><div class="flex items-center gap-2"><p class="font-bold text-g900 text-[16px] truncate">${esc(a.brand_name)}</p>${statusBadge(a.status)}${holdBadge(a)}${rejBtn(a)}${wfOf(a).step>=7?statusBadge(a.pay_status||"결제 대기중"):""}${on?'<span class="text-[11px] font-bold text-blue">선택됨</span>':''}</div><p class="text-[13px] text-g500 mt-1 truncate">${(a.channels||[]).map(c=>c.name+(c.qty>1?" ×"+c.qty:"")).join(", ")||"채널 미선택"}</p><p class="text-[12px] font-bold text-blue mt-1 truncate">${wfOf(a).step>=7?"제작 완료 · 리포트 단계":(WF[wfOf(a).step-1]?WF[wfOf(a).step-1].t:"진행 중")}</p></div><div class="text-right flex-shrink-0"><p class="text-[16px] font-bold text-blue num">${wonM(a.total_amount||0)}</p><button onclick="event.stopPropagation();campDetail('${a.id}')" class="text-[12px] text-g500 font-bold underline">신청내용</button></div></div>`;}).join("");if(window.lucide)lucide.createIcons();}
function viewCustomerDashboard(){setTimeout(loadMyCamps,30);const c=S.activeCamp;const wf=c?wfOf(c):{step:1};const cur=Math.min(wf.step,7);const bn=(S.cust&&S.cust.brand)?S.cust.brand:"고객";const pct=Math.round(Math.min(cur,7)/7*100);
const todoMap={1:["승인 후 진행됩니다"],2:["소재·가이드 파일 업로드 후 제출"],3:["크놀AD 콘티 작성 대기"],4:["전달된 콘티 컨펌 또는 수정 요청"],5:["크놀AD 영상 제작 대기"],6:["전달된 영상 컨펌 또는 수정 요청"],7:["리포트에서 업로드·성과 확인","결제(정산) 진행"]};
const todo=todoMap[cur]||["진행 대기 중"];
const stageLabel=cur>=7?"완료 · 리포트 단계":(WF[cur-1]?WF[cur-1].t:"대기");
const steps=WF.map((st,i)=>{const idx=i+1;const done=idx<cur,act=idx===cur;return `<div class="flex items-center gap-3 px-3 py-2.5 rounded-2xl ${act?'bg-blue-tint':''}"><div class="w-6 h-6 rounded-full grid place-items-center flex-shrink-0 text-[12px] font-bold ${done?'bg-emerald-500 text-white':act?'bg-blue text-white':'bg-g200 text-g500'}">${done?'<i data-lucide="check" class="w-3 h-3"></i>':idx}</div><span class="text-[15px] flex-1 ${done?'text-g400 line-through':act?'text-g900 font-bold':'text-g500'}">${st.t}</span>${done?'<span class="text-[13px] text-emerald-600 font-bold">완료</span>':act?'<span class="text-[13px] text-blue font-bold">진행중</span>':'<span class="text-[13px] text-g300">대기</span>'}</div>`;}).join("");
return `<div class="p-8 md:p-10">${pageHeader("CAMPAIGN","캠페인 관리",esc(bn)+" 님의 캠페인 현황입니다. 캠페인을 누르면 신청 내용을 볼 수 있어요.")}
<div class="grid lg:grid-cols-3 gap-4 mb-4"><div class="${CARD} lg:col-span-2 p-7"><div class="flex items-center justify-between mb-4"><h2 class="text-[18px] font-bold text-g900">내 캠페인</h2><button onclick="newApply()" class="text-[14px] text-blue font-bold inline-flex items-center gap-1"><i data-lucide="plus" class="w-4 h-4"></i>캠페인 추가 신청</button></div><div id="myCampWrap" class="space-y-2"><div class="text-g400 text-center py-8 text-[15px]">불러오는 중…</div></div></div>
<div class="${CARD} p-7 flex flex-col items-center justify-center text-center"><p class="text-[14px] text-g400 mb-1">진행 단계</p><div class="font-display text-[48px] font-bold text-g900 num leading-none">${Math.min(cur,6)}<span class="text-[24px] text-g300">/6</span></div><p class="text-[13px] text-g500 mb-3">${esc(stageLabel)}</p><div class="w-full bg-g100 rounded-full h-2 mb-3"><div class="bg-blue h-2 rounded-full transition-all" style="width:${pct}%"></div></div><button onclick="go('workflow')" class="text-[15px] text-blue font-bold">워크플로우 진행하기 →</button></div></div>
<div class="grid lg:grid-cols-2 gap-4"><div class="${CARD} p-7"><h2 class="text-[16px] font-bold text-g900 mb-4">진행 단계</h2><div class="space-y-0.5">${steps}</div></div><div class="${CARD} p-7"><h2 class="text-[16px] font-bold text-g900 mb-3">현재 할 일</h2>${todo.map(it=>`<div class="flex items-center gap-3 py-1.5"><div class="w-2 h-2 rounded-full bg-blue flex-shrink-0"></div><span class="text-[16px] text-g700">${it}</span></div>`).join("")}<button onclick="go('workflow')" class="${BTN} w-full mt-4 py-3">워크플로우에서 처리하기</button></div></div></div>`;}
function viewMyPage(){setTimeout(loadMyCamps,30);const c=S.cust||{};const a=S.activeCamp||(S.myCamps&&S.myCamps[0])||{};const kv=(k,v)=>`<div class="flex justify-between py-2 border-b border-g100 last:border-0"><span class="text-g500 text-[15px]">${k}</span><span class="font-bold text-g900 text-[15px] text-right break-all">${esc(v||'-')}</span></div>`;
return `<div class="p-8 md:p-10"><div class="max-w-2xl">${pageHeader("MY PAGE","마이페이지","신청 정보 기준으로 생성된 내 정보입니다")}
<div class="${CARD} p-7 mb-4"><h2 class="text-[16px] font-bold text-g900 mb-3">내 정보</h2>${kv("담당자",c.name||a.contact_name)}${kv("아이디(이메일)",c.email||a.email)}${kv("연락처",a.phone)}${kv("회사/브랜드",c.brand||a.brand_name)}</div>
<div class="${CARD} p-7 mb-4"><h2 class="text-[16px] font-bold text-g900 mb-3">최근 신청 정보</h2>${kv("업로드 희망일",a.preferred_date)}${kv("희망 채널",(a.channels||[]).map(x=>x.name).join(", "))}${kv("활용 소재",a.material)}${kv("광고 고지 방식",a.ad_disclosure)}${kv("금액 (VAT 별도)",wonM(a.total_amount||0))}</div>
<div class="${CARD} p-7"><h2 class="text-[16px] font-bold text-g900 mb-1">사업자등록증 제출</h2><p class="text-[14px] text-g500 mb-3 leading-relaxed">세금계산서는 <b>크놀AD(에이치알컴퍼니)</b>가 발행합니다. 발행을 위해 사업자등록증을 제출해주세요.</p>${uploadZone("bizFile","사업자등록증 이미지 또는 PDF")}<button onclick="submitBiz()" class="${BTN} w-full mt-3">사업자등록증 제출</button></div>
</div></div>`;}
function submitBiz(){const c=S.activeCamp;if(c){fetch(SUPA_URL+"/rest/v1/knollad_applications?id=eq."+c.id,{method:"PATCH",headers:Object.assign({"Content-Type":"application/json","Prefer":"return=minimal"},SH),body:JSON.stringify({biz_reg:"제출됨"})}).catch(()=>{});}toast("사업자등록증이 제출되었습니다");}
function uploadZone(id,hint){id=id||"fileList";return `<label class="block border-2 border-dashed border-g300 rounded-[20px] p-7 text-center cursor-pointer hover:border-blue hover:bg-blue-soft transition-all"><input type="file" multiple class="hidden" onchange="showFiles(this,'${id}')"><i data-lucide="upload-cloud" class="w-9 h-9 text-g400 mx-auto mb-2"></i><p class="text-[17px] font-bold text-g700">파일을 끌어다 놓거나 클릭해서 업로드</p><p class="text-[14px] text-g400 mt-1">${hint||"제품 이미지·영상·로고·가이드 등 (여러 개 가능)"}</p></label><div id="${id}" class="space-y-2 mt-3"></div>`;}
function showFiles(input,id){const el=document.getElementById(id||"fileList");if(!el)return;const fs=[...input.files];el.innerHTML=fs.map(f=>`<div class="flex items-center gap-2 bg-g50 rounded-2xl px-3 py-2 text-[15px]"><i data-lucide="file" class="w-4 h-4 text-blue flex-shrink-0"></i><span class="flex-1 truncate text-g700">${esc(f.name)}</span><span class="text-g400 text-[12px] num">${(f.size/1024).toFixed(0)}KB</span></div>`).join("");if(window.lucide)lucide.createIcons();if(fs.length)toast(fs.length+"개 파일 선택됨");}
function wfSave(patch){const c=S.activeCamp;if(!c){toast("진행할 캠페인이 없습니다");return;}const wf=Object.assign({},wfOf(c),patch);c.wf=wf;fetch(SUPA_URL+"/rest/v1/knollad_applications?id=eq."+c.id,{method:"PATCH",headers:Object.assign({"Content-Type":"application/json","Prefer":"return=minimal"},SH),body:JSON.stringify({wf})}).then(r=>{if(!r.ok)toast("저장 실패");}).catch(()=>toast("저장 오류"));render();}
function wfDataSubmit(){const link=(gv("wfRef")||"").trim();const fi=document.getElementById("wfData");if(fi&&fi.files&&fi.files.length){uploadToStorage("wfData",function(url){wfSave({step:2,note:null,dataUrl:url,dataLink:link||null});toast(isSimpleWf(S.activeCamp)?"영상이 제출되었습니다 · 크놀AD 검수 후 업로드가 진행됩니다":"자료가 제출되었습니다 · 크놀AD 확인 후 콘티 제작이 시작됩니다");});}else if(link){wfSave({step:2,note:null,dataLink:link});toast(isSimpleWf(S.activeCamp)?"영상 링크가 제출되었습니다 · 크놀AD 검수 후 업로드가 진행됩니다":"링크가 제출되었습니다 · 크놀AD 확인 후 콘티 제작이 시작됩니다");}else{toast("파일을 올리거나 링크를 입력해주세요");}}
function wfConfirm(){const wf=activeWf();var _cf=(wf.step===4?"콘티 컨펌":(wf.step===6?"영상 컨펌":null));if(wf.step===4)wfSave({step:5});else if(wf.step===6)wfSave({step:7});if(_cf){try{var _cc=S.activeCamp||{};notifyTelegram("✅ ["+_cf+"] "+((_cc.brand_name)||"캠페인")+" — "+((S.cust&&(S.cust.name||S.cust.email))||"고객"));}catch(_te){}}toast("컨펌되었습니다 · 다음 단계로 진행됩니다");}
function wfReqEdit(){var t=(gv("wfFb")||"").trim();var wf=activeWf();var c=S.activeCamp;var _stg=(wf.step===4?"콘티":(wf.step===6?"영상":""));uploadMany("wfFbFile",function(urls){if(c){var notes=(c.notes||[]).slice();notes.push({who:(S.cust&&S.cust.name)||"고객",role:"cust",text:"[수정요청"+(_stg?(" · "+_stg):"")+"]"+(t?(" "+t):""),at:new Date().toISOString()});(urls||[]).forEach(function(u){notes.push({who:(S.cust&&S.cust.name)||"고객",role:"cust",fileUrl:u,at:new Date().toISOString()});});c.notes=notes;fetch(SUPA_URL+"/rest/v1/knollad_applications?id=eq."+c.id,{method:"PATCH",headers:Object.assign({"Content-Type":"application/json","Prefer":"return=minimal"},SH),body:JSON.stringify({notes:notes})}).catch(function(){});}if(wf.step===4)wfSave({step:3,conti:null,note:t||null});else if(wf.step===6)wfSave({step:5,video:null,note:t||null});try{notifyTelegram("✏️ [수정요청"+(_stg?(" · "+_stg):"")+"] "+((c&&c.brand_name)||"캠페인")+" — "+((S.cust&&(S.cust.name||S.cust.email))||"고객")+(t?(": "+t):""));}catch(_te){}toast("수정 요청이 전달되었습니다 · 크놀AD가 반영 후 재전달합니다");});}
function openLink(u){if(!u){toast("링크가 아직 없습니다");return;}window.open(u,"_blank");}

var _cnLogosDone=false;
function cnLoadLogos(){if(_cnLogosDone)return;_cnLogosDone=true;var ids=CH.map(function(c){return c.id;}).filter(Boolean),i;for(i=0;i<ids.length;i+=50){var chunk=ids.slice(i,i+50);fetch("https://www.googleapis.com/youtube/v3/channels?part=snippet&maxResults=50&key="+YT_API_KEY+"&id="+chunk.join(",")).then(function(r){return r.json();}).then(function(d){var hit=false;(d.items||[]).forEach(function(it){var c=CH.find(function(x){return x.id===it.id;});if(c&&it.snippet&&it.snippet.thumbnails){var th=it.snippet.thumbnails;var u=((th.medium||th.default||th.high)||{}).url||null;if(u){c.logo=u;hit=true;}}});if(hit&&typeof render==="function"&&typeof S!=="undefined"&&["apply","cust-apply","channels","cust-channels","channel-picker","channel-detail"].indexOf(S.view)>=0){if(typeof saveForm==="function"){try{saveForm();}catch(e){}}render();}}).catch(function(){});}}
window.addEventListener("load",function(){try{cnLoadLogos();}catch(e){}});
function kkoTime(at){if(!at)return "";var d=new Date(at);if(isNaN(d.getTime()))return "";var h=d.getHours(),m=d.getMinutes();var ap=h<12?"오전":"오후";var hh=h%12;if(hh===0)hh=12;return ap+" "+hh+":"+(m<10?"0"+m:m);}
function kkoDateTime(at){if(!at)return "";var d=new Date(at);if(isNaN(d.getTime()))return "";var y=d.getFullYear(),mo=d.getMonth()+1,da=d.getDate();return y+"."+(mo<10?"0"+mo:mo)+"."+(da<10?"0"+da:da)+" "+kkoTime(at);}
function kkoMine(nt){var isK=(nt.role==="knoll"||nt.who==="크놀AD");return (typeof S!=="undefined"&&S.role==="admin")?isK:(nt.role==="cust"||nt.who==="고객"||(typeof S!=="undefined"&&S.cust&&nt.who===S.cust.name));}
function kkoUnread(idx,arr,mine){if(!arr||typeof idx!=="number")return false;for(var j=idx+1;j<arr.length;j++){if(kkoMine(arr[j])!==mine)return false;}return true;}
function csMine(m){return (m.role==="cust"||m.who==="고객"||(typeof S!=="undefined"&&S.cust&&m.who===S.cust.name));}
function csUnread(idx,arr){if(!arr||typeof idx!=="number")return false;for(var j=idx+1;j<arr.length;j++){if(!csMine(arr[j]))return false;}return true;}
function kakaoNoteRow(nt,idx,arr){
var isKnoll=(nt.role==="knoll"||nt.who==="크놀AD");
var me=(S.role==="admin")?isKnoll:(nt.role==="cust"||nt.who==="고객"||(S.cust&&nt.who===S.cust.name));
var time=kkoTime(nt.at);
var av=isKnoll?logoMark("w-9 h-9"):'<div class="w-9 h-9 rounded-[14px] grid place-items-center font-bold text-[14px] flex-shrink-0" style="background:#dfe4ea;color:#4b5563">'+esc(String(nt.who||"고").charAt(0))+'</div>';
var inner="";
if(nt.title)inner+='<p class="text-[15px] font-bold mb-1">'+esc(nt.title)+'</p>';
if(nt.text)inner+='<p class="text-[15px] whitespace-pre-wrap leading-relaxed break-words">'+esc(nt.text)+'</p>';
if(nt.fileUrl||nt.link){inner+='<div class="mt-2 flex gap-3">';
if(nt.fileUrl)inner+='<button onclick="openLink(\''+esc(nt.fileUrl)+'\')" class="text-[13px] font-bold underline" style="color:#1a56db">첨부파일 ↗</button>';
if(nt.link)inner+='<button onclick="openLink(\''+esc(nt.link)+'\')" class="text-[13px] font-bold underline" style="color:#1a56db">링크 ↗</button>';
inner+='</div>';}
var bub='<div class="rounded-[14px] px-3.5 py-2.5" style="'+(me?'background:#FEE500;color:#191600':'background:#ffffff;color:#191919')+';box-shadow:0 1px 1.5px rgba(0,0,0,.08)">'+inner+'</div>';
var unread=me&&kkoUnread(idx,arr,true);var tm='<span class="flex-shrink-0 pb-0.5 inline-flex flex-col items-end" style="line-height:1.25">'+(unread?'<b style="color:#e5a50a;font-size:11px">1</b>':"")+'<span class="text-[11px]" style="color:#111827;font-weight:600">'+time+'</span></span>';
if(me)return '<div class="flex justify-end items-start gap-2"><div class="flex items-end gap-1.5 max-w-[78%] min-w-0">'+tm+'<div class="min-w-0">'+bub+'</div></div>'+av+'</div>';
return '<div class="flex justify-start items-start gap-2">'+av+'<div class="max-w-[78%] min-w-0"><p class="text-[12px] font-bold mb-1" style="color:#3d4a56">'+esc(String(nt.who||""))+'</p><div class="flex items-end gap-1.5"><div class="min-w-0">'+bub+'</div>'+tm+'</div></div></div>';
}
function kkoFix(){
try{
var st=document.getElementById("kkoChat");
if(!st){st=document.createElement("style");st.id="kkoChat";document.head.appendChild(st);}
st.textContent="#chatScroll{background:#b2c7d9!important;display:flex!important;flex-direction:column!important}"
+"#csScroll{display:flex!important;flex-direction:column!important}"
+"#acScroll{display:flex!important;flex-direction:column!important}"
;
var cs=document.getElementById("chatScroll");
if(cs&&cs.parentElement&&cs.parentElement.style&&cs.parentElement.style.height){cs.parentElement.style.height="84vh";}
if(cs){cs.scrollTop=cs.scrollHeight;}
var sc=document.getElementById("csScroll");if(sc){sc.scrollTop=sc.scrollHeight;}
var ac=document.getElementById("acScroll");if(ac){ac.scrollTop=ac.scrollHeight;}
var hs=document.querySelectorAll("h3,h2");
for(var i=0;i<hs.length;i++){
var txt=(hs[i].textContent||"").trim();
if(txt==="현재 진행 상황"){
var g=hs[i].closest("div.grid");
if(g&&g.children.length===2){g.children[0].style.order="2";g.children[1].style.order="1";}
}
if(txt.indexOf("메시지")===0&&txt.indexOf("고객 소통")>0){
var card=hs[i].parentElement;
if(card){var inner=card.querySelector('[style*="46vh"]')||card.querySelector("[data-kko]");if(inner){inner.setAttribute("data-kko","1");inner.style.height="64vh";inner.style.background="#b2c7d9";inner.style.borderRadius="16px";inner.style.padding="12px";inner.style.display="flex";inner.style.flexDirection="column";inner.style.gap="10px";inner.style.overflowY="auto";inner.scrollTop=inner.scrollHeight;}var ta=card.querySelector("textarea");if(ta){ta.style.border="1px solid #d5dae0";ta.style.borderRadius="12px";ta.style.padding="10px 12px";ta.style.background="#fff";ta.style.outline="none";ta.style.width="100%";ta.style.resize="none";ta.style.minHeight="46px";var box=ta.parentElement;while(box&&box.parentElement&&box.parentElement!==card)box=box.parentElement;if(box&&box!==ta&&!box.hasAttribute("data-kkobox")){box.setAttribute("data-kkobox","1");box.style.border="1px solid #d5dae0";box.style.borderRadius="16px";box.style.padding="10px";box.style.background="#fff";box.style.marginTop="10px";}var fi=card.querySelector('input[type="file"]');if(fi){fi.style.fontSize="12px";fi.style.maxWidth="100%";fi.style.marginTop="6px";}}}
}
}
kkoPayFix();
}catch(e){}
}
function kkoPayFix(){try{
if(typeof S==="undefined"||S.view!=="settlement")return;
if(document.getElementById("kkoPayNote"))return;
var g=document.querySelector(".max-w-5xl > .grid");if(!g||!g.parentElement)return;
var d=document.createElement("div");d.id="kkoPayNote";
d.style.cssText="background:#eef4ff;border:1px solid #cddffb;border-radius:16px;padding:14px 16px;margin-bottom:16px";
d.innerHTML='<p style="font-weight:800;color:#111827;font-size:15.5px;margin-bottom:6px">입금 안내</p>'
+'<p style="font-size:14.5px;color:#374151;line-height:1.7;word-break:keep-all">세금계산서 <b>발행 후 바로 입금</b>해 주세요. (월말 일괄 정산이 아닙니다)</p>'
+'<p style="font-size:14.5px;color:#111827;line-height:1.7;margin-top:6px;word-break:keep-all">예금주 <b>에이치알컴퍼니 주식회사</b> · <b>우리은행</b> 계좌번호 <b>1005-504-167163</b></p>';
g.parentElement.insertBefore(d,g);
}catch(e){}}
window.addEventListener("load",function(){try{
window.noteRow=kakaoNoteRow;
if(typeof render==="function"&&!window.__kkoWrapped){
var _r=render;window.__kkoWrapped=true;
window.render=function(){var v=_r.apply(this,arguments);setTimeout(kkoFix,0);return v;};
}
kkoFix();
if(typeof render==="function"&&typeof S!=="undefined"&&S.view)render();
}catch(e){}});
